import SwiftUIstruct OnlineLobbyView: View {    @State private var playerName: String = ""    @State private var joinCode: String = ""    @State private var isCreating: Bool = false    @State private var isJoining: Bool = false    @State private var errorMessage: String?    @State private var navigateToWaiting: Bool = false    @State private var gameId: String = ""    @StateObject private var gameService = GameService()        var body: some View {        ScrollView {            VStack(spacing: 28) {                                // ── Header ──                VStack(spacing: 8) {                    Text("🌐 Online Game")                        .font(.largeTitle.bold())                        .foregroundStyle(AppTheme.primaryText)                    Text("Create or join a game")                        .foregroundStyle(AppTheme.secondaryText)                }                .padding(.top, 32)                                // ── Name Input ──                VStack(alignment: .leading, spacing: 8) {                    Text("Your Name")                        .font(.headline)                        .foregroundStyle(AppTheme.primaryText)                    TextField("Enter your name", text: $playerName)                        .textFieldStyle(.roundedBorder)                        .autocorrectionDisabled()                }                .padding(.horizontal)                                // ── Create Game ──                VStack(spacing: 12) {                    Text("Create a new game")                        .font(.headline)                        .foregroundStyle(AppTheme.primaryText)                        .frame(maxWidth: .infinity, alignment: .leading)                                        Button {                        Task { await createGame() }                    } label: {                        HStack {                            if isCreating {                                ProgressView()                                    .tint(.white)                                    .padding(.trailing, 8)                            }                            Text(isCreating ? "Creating..." : "Create Game")                                .font(.headline)                        }                        .frame(maxWidth: .infinity)                        .padding()                        .background(playerName.isEmpty                            ? Color.gray : AppTheme.accent)                        .foregroundStyle(.white)                        .clipShape(RoundedRectangle(cornerRadius: 14))                    }                    .disabled(playerName.isEmpty || isCreating)                }                .padding(.horizontal)                                // ── Divider ──                HStack {                    Rectangle().frame(height: 1)                        .foregroundStyle(AppTheme.cardBackground)                    Text("OR")                        .foregroundStyle(AppTheme.secondaryText)                        .font(.subheadline)                    Rectangle().frame(height: 1)                        .foregroundStyle(AppTheme.cardBackground)                }                .padding(.horizontal)                                // ── Join Game ──                VStack(spacing: 12) {                    Text("Join an existing game")                        .font(.headline)                        .foregroundStyle(AppTheme.primaryText)                        .frame(maxWidth: .infinity, alignment: .leading)                                        TextField("Enter 6-digit code", text: $joinCode)                        .textFieldStyle(.roundedBorder)                        .textInputAutocapitalization(.characters)                        .autocorrectionDisabled()                        .onChange(of: joinCode) { newValue in                            joinCode = String(                                newValue.uppercased().prefix(6)                            )                        }                                        Button {                        Task { await joinGame() }                    } label: {                        HStack {                            if isJoining {                                ProgressView()                                    .tint(.white)                                    .padding(.trailing, 8)                            }                            Text(isJoining ? "Joining..." : "Join Game")                                .font(.headline)                        }                        .frame(maxWidth: .infinity)                        .padding()                        .background(                            playerName.isEmpty || joinCode.count < 6                                ? Color.gray : AppTheme.accent                        )                        .foregroundStyle(.white)                        .clipShape(RoundedRectangle(cornerRadius: 14))                    }                    .disabled(                        playerName.isEmpty ||                        joinCode.count < 6 ||                        isJoining                    )                }                .padding(.horizontal)                                // ── Error ──                if let error = errorMessage {                    Text(error)                        .foregroundStyle(AppTheme.accent)                        .font(.subheadline)                        .padding(.horizontal)                }            }        }        .background(AppTheme.background)        .scrollContentBackground(.hidden)        .navigationTitle("")        .navigationBarTitleDisplayMode(.inline)        .navigationDestination(isPresented: $navigateToWaiting) {            WaitingRoomView(                gameId: gameId,                gameService: gameService            )        }    }        private func createGame() async {        guard !playerName.isEmpty else { return }        isCreating = true        errorMessage = nil        do {            gameId = try await gameService.createGame(                hostName: playerName            )            navigateToWaiting = true        } catch {            errorMessage = error.localizedDescription        }        isCreating = false    }        private func joinGame() async {        guard !playerName.isEmpty, joinCode.count == 6 else { return }        isJoining = true        errorMessage = nil        do {            gameId = try await gameService.joinGame(                code: joinCode,                playerName: playerName            )            navigateToWaiting = true        } catch {            errorMessage = error.localizedDescription        }        isJoining = false    }}